blocks.code:
self.whir_round_encoder.eval(builder, &local.whir_round_enc);

// Constrain whir_round column to match the decoded encoder value
let round_flag_vals: Vec<_> = (0..self.num_rounds).map(|r| (r, r)).collect();
let whir_round_decoded = self
    .whir_round_encoder
    .flag_with_val::<AB>(&local.whir_round_enc, &round_flag_vals);
builder
    .when(is_enabled)
    .assert_eq(local.whir_round, whir_round_decoded);

// Constrain num_queries column to match the expected value for this round
let num_queries_flag_vals: Vec<_> = self
    .num_queries_per_round
    .iter()
    .enumerate()
    .map(|(r, &nq)| (r, nq))
    .collect();
let expected_num_queries = self
    .whir_round_encoder
    .flag_with_val::<AB>(&local.whir_round_enc, &num_queries_flag_vals);
builder
    .when(is_enabled)
    .assert_eq(local.num_queries, expected_num_queries);

let initial_omega = AB::Expr::from_prime_subfield(
    <<AB::Expr as PrimeCharacteristicRing>::PrimeSubfield as TwoAdicField>::two_adic_generator(
        self.initial_log_domain_size,
    ),
);
builder
    .when(is_proof_start)
    .assert_eq(local.omega, initial_omega);

// Use the column (degree 1) instead of decoded expression (high degree) for constraints
let whir_round: AB::Expr = local.whir_round.into();
let is_same_proof = next.is_enabled - next.is_first_in_proof;
builder
    .when(is_same_proof.clone())
    .assert_eq(next.omega, local.omega * local.omega);

NestedForLoopSubAir.eval(
    builder,
    (
        NestedForLoopIoCols {
            is_enabled,
            counter: [local.proof_idx, local.whir_round],
            is_first: [local.is_first_in_proof, is_enabled],
        }
        .map_into(),
        NestedForLoopIoCols {
            is_enabled: next.is_enabled,
            counter: [next.proof_idx, next.whir_round],
            is_first: [next.is_first_in_proof, next.is_enabled],
        }
        .map_into(),
    ),
);

builder
    .when(local.is_enabled - is_same_proof.clone())
    .assert_eq(local.whir_round, AB::Expr::from_usize(self.num_rounds - 1));

assert_array_eq(
    &mut builder.when(is_same_proof.clone()),
    next.claim,
    local.next_claim,
);

self.whir_module_bus.receive(
    builder,
    proof_idx,
    WhirModuleMessage {
        tidx: local.tidx,
        claim: local.claim,
    },
    is_proof_start,
);
self.commitments_bus.add_key_with_lookups(
    builder,
    proof_idx,
    CommitmentsBusMessage {
        major_idx: whir_round.clone() + AB::Expr::ONE,
        minor_idx: AB::Expr::ZERO,
        commitment: local.commit.map(Into::into),
    },
    is_same_proof.clone() * next.num_queries,
);

self.sumcheck_bus.send(
    builder,
    proof_idx,
    WhirSumcheckBusMessage {
        tidx: local.tidx.into(),
        sumcheck_idx: whir_round.clone() * AB::Expr::from_usize(self.k),
        pre_claim: local.claim.map(Into::into),
        post_claim: local.post_sumcheck_claim.map(Into::into),
    },
    is_enabled,
);

let folding_pow_offset = pow_tidx_count(self.folding_pow_bits);
let query_pow_offset = pow_tidx_count(self.pow_bits);
let post_sumcheck_offset = (3 * D_EF + folding_pow_offset) * self.k;
let mut non_final_round_offset = post_sumcheck_offset;

self.transcript_bus.observe_commit(
    builder,
    proof_idx,
    local.tidx + AB::Expr::from_usize(non_final_round_offset),
    local.commit,
    is_same_proof.clone(),
);
non_final_round_offset += DIGEST_SIZE;

self.transcript_bus.sample_ext(
    builder,
    proof_idx,
    local.tidx + AB::Expr::from_usize(non_final_round_offset),
    local.z0,
    is_same_proof.clone(),
);
non_final_round_offset += D_EF;
self.transcript_bus.observe_ext(
    builder,
    proof_idx,
    local.tidx + AB::Expr::from_usize(non_final_round_offset),
    local.y0,
    is_same_proof.clone(),
);
non_final_round_offset += D_EF;

self.query_bus.send(
    builder,
    proof_idx,
    WhirQueryBusMessage {
        whir_round: whir_round.clone(),
        query_idx: AB::Expr::ZERO,
        value: local.z0.map(|z0_i| z0_i * is_same_proof.clone()),
    },
    is_enabled,
);
self.final_poly_mle_eval_bus.send(
    builder,
    proof_idx,
    FinalPolyMleEvalMessage {
        tidx: local.tidx + AB::Expr::from_usize(post_sumcheck_offset),
        num_whir_rounds: whir_round.clone() + AB::Expr::ONE,
        value: local.final_poly_mle_eval.map(Into::into),
    },
    local.is_enabled - is_same_proof.clone(),
);
self.final_poly_query_eval_bus.send(
    builder,
    proof_idx,
    FinalPolyQueryEvalMessage {
        last_whir_round: whir_round.clone() + AB::Expr::ONE,
        value: ext_field_subtract(local.next_claim, local.final_poly_mle_eval),
    },
    local.is_enabled - is_same_proof.clone(),
);

let final_round_offset = post_sumcheck_offset + D_EF * self.final_poly_len;
let pow_tidx = local.tidx
    + (local.is_enabled - is_same_proof.clone()) * AB::Expr::from_usize(final_round_offset)
    + is_same_proof.clone() * AB::Expr::from_usize(non_final_round_offset);

if self.pow_bits > 0 {
    self.transcript_bus.observe(
        builder,
        proof_idx,
        pow_tidx.clone(),
        local.query_pow_witness,
        is_enabled,
    );
    self.transcript_bus.sample(
        builder,
        proof_idx,
        pow_tidx.clone() + AB::Expr::ONE,
        local.query_pow_sample,
        is_enabled,
    );

    // Check proof-of-work using `ExpBitsLenBus`.
    self.exp_bits_len_bus.lookup_key(
        builder,
        ExpBitsLenMessage {
            base: self.generator.into(),
            bit_src: local.query_pow_sample.into(),
            num_bits: AB::Expr::from_usize(self.pow_bits),
            result: AB::Expr::ONE,
        },
        is_enabled,
    );
}

    let verify_query_tidx = pow_tidx.clone() + AB::Expr::from_usize(query_pow_offset);
    let y0_gated: [AB::Expr; D_EF] = local.y0.map(|y| y * is_same_proof.clone());

    self.verify_queries_bus.send(
        builder,
        proof_idx,
        VerifyQueriesBusMessage {
            tidx: verify_query_tidx,
            whir_round: whir_round.clone(),
            num_queries: local.num_queries.into(),
            omega: local.omega.into(),
            gamma: local.gamma.map(Into::into),
            pre_claim: ext_field_add(
                local.post_sumcheck_claim,
                ext_field_multiply(local.gamma, y0_gated),
            ),
            post_claim: local.next_claim.map(Into::into),
        },
        is_enabled,
    );

    self.transcript_bus.sample_ext(
        builder,
        proof_idx,
        pow_tidx.clone() + AB::Expr::from_usize(query_pow_offset) + local.num_queries,
        local.gamma,
        is_enabled,
    );
    builder.when(is_same_proof).assert_eq(
        next.tidx,
        pow_tidx.clone() + AB::Expr::from_usize(query_pow_offset + D_EF) + local.num_queries,
    );
    self.gamma_bus.send(
        builder,
        proof_idx,
        WhirGammaMessage {
            idx: whir_round.clone(),
            challenge: local.gamma.map(Into::into),
        },
        is_enabled,
    );
}

#[repr(C)]
#[derive(AlignedBorrow)]
pub struct SumcheckCols<T> {
    pub is_enabled: T,
    pub proof_idx: T,
    pub whir_round: T,
    /// A counter that goes from 0 to k_whir - 1.
    pub subidx: T,
    pub is_first_in_proof: T,
    pub is_first_in_round: T,
    /// The transcript index at the beginning of the current sumcheck round.
    pub tidx: T,
    pub ev1: [T; D_EF],
    pub ev2: [T; D_EF],
    pub folding_pow_witness: T,
    pub folding_pow_sample: T,
    pub alpha: [T; D_EF],
    pub u: [T; D_EF],
    /// The claim at the beginning of the sumcheck round.
    pub pre_claim: [T; D_EF],
    /// The claim at the end of the group of sumcheck rounds.
    pub post_group_claim: [T; D_EF],
    /// The value `eq_i(alpha, u)` on the ith sumcheck row (within a proof).
    pub eq_partial: [T; D_EF],
    /// The number of times the challenge `alpha` is looked up by other AIRs. This is
    /// unconstrained.
    pub alpha_lookup_count: T,
}

let proof_idx = local.proof_idx;
let is_enabled = local.is_enabled;
let is_same_proof = next.is_enabled - next.is_first_in_proof;
let is_same_round = next.is_enabled - next.is_first_in_round;

NestedForLoopSubAir::<3>.eval(
    builder,
    (
        NestedForLoopIoCols {
            is_enabled: local.is_enabled,
            counter: [local.proof_idx, local.whir_round, local.subidx],
            is_first: [
                local.is_first_in_proof,
                local.is_first_in_round,
                local.is_enabled,
            ],
        }
        .map_into(),
        NestedForLoopIoCols {
            is_enabled: next.is_enabled,
            counter: [next.proof_idx, next.whir_round, next.subidx],
            is_first: [
                next.is_first_in_proof,
                next.is_first_in_round,
                next.is_enabled,
            ],
        }
        .map_into(),
    ),
);

builder
    .when(local.is_enabled - is_same_round.clone())
    .assert_eq(local.subidx, AB::Expr::from_usize(self.k - 1));

let sumcheck_idx = local.whir_round * AB::Expr::from_usize(self.k) + local.subidx;
self.sumcheck_bus.receive(
    builder,
    proof_idx,
    WhirSumcheckBusMessage {
        tidx: local.tidx.into(),
        sumcheck_idx: sumcheck_idx.clone(),
        pre_claim: local.pre_claim.map(Into::into),
        post_claim: local.post_group_claim.map(Into::into),
    },
    local.is_first_in_round,
);

let post_claim = interpolate_quadratic(local.pre_claim, local.ev1, local.ev2, local.alpha);
assert_array_eq(
    &mut builder.when(local.is_enabled - is_same_round.clone()),
    post_claim.clone(),
    local.post_group_claim,
);

let mut when_sumcheck_transition = builder.when(is_same_round.clone());
when_sumcheck_transition.assert_zero(next.is_first_in_round);
assert_array_eq(&mut when_sumcheck_transition, post_claim, next.pre_claim);
assert_array_eq(
    &mut when_sumcheck_transition,
    next.post_group_claim,
    local.post_group_claim,
);
let folding_pow_offset = pow_tidx_count(self.folding_pow_bits);
when_sumcheck_transition.assert_eq(
    next.tidx,
    local.tidx + AB::Expr::from_usize(3 * D_EF + folding_pow_offset),
);

// Use Möbius-adjusted equality kernel instead of eq_1 for eval-to-coeff RS encoding.
assert_array_eq(
    &mut builder.when(is_same_proof.clone()),
    next.eq_partial,
    ext_field_multiply::<AB::Expr>(
        local.eq_partial,
        mobius_eq_1::<AB::Expr>(next.u, next.alpha),
    ),
);

assert_array_eq(
    &mut builder.when(local.is_first_in_proof),
    local.eq_partial,
    mobius_eq_1::<AB::Expr>(local.u, local.alpha),
);

self.transcript_bus
    .observe_ext(builder, proof_idx, local.tidx, local.ev1, is_enabled);
self.transcript_bus.observe_ext(
    builder,
    proof_idx,
    local.tidx + AB::Expr::from_usize(D_EF),
    local.ev2,
    is_enabled,
);
if self.folding_pow_bits > 0 {
    self.transcript_bus.observe(
        builder,
        proof_idx,
        local.tidx + AB::Expr::from_usize(2 * D_EF),
        local.folding_pow_witness,
        is_enabled,
    );
    self.transcript_bus.sample(
        builder,
        proof_idx,
        local.tidx + AB::Expr::from_usize(2 * D_EF + 1),
        local.folding_pow_sample,
        is_enabled,
    );
}
self.transcript_bus.sample_ext(
    builder,
    proof_idx,
    local.tidx + AB::Expr::from_usize(2 * D_EF + folding_pow_offset),
    local.alpha,
    is_enabled,
);

if self.folding_pow_bits > 0 {
    self.exp_bits_len_bus.lookup_key(
        builder,
        ExpBitsLenMessage {
            base: self.generator.into(),
            bit_src: local.folding_pow_sample.into(),
            num_bits: AB::Expr::from_usize(self.folding_pow_bits),
            result: AB::Expr::ONE,
        },
        is_enabled,
    );
}

    self.alpha_bus.add_key_with_lookups(
        builder,
        proof_idx,
        WhirAlphaMessage {
            idx: sumcheck_idx.clone(),
            challenge: local.alpha.map(Into::into),
        },
        local.is_enabled * local.alpha_lookup_count,
    );
    self.eq_alpha_u_bus.send(
        builder,
        proof_idx,
        WhirEqAlphaUMessage {
            value: local.eq_partial,
        },
        local.is_enabled - is_same_proof.clone(),
    );
    self.whir_opening_point_bus.receive(
        builder,
        proof_idx,
        WhirOpeningPointMessage {
            idx: sumcheck_idx,
            value: local.u.map(Into::into),
        },
        is_enabled,
    );
}

assert_array_eq(
    &mut builder.when(local.is_first_in_round),
    local.gamma_pow,
    ext_field_multiply::<AB::Expr>(local.gamma, local.gamma),
);

builder
    .when(local.is_enabled - is_same_round.clone())
    .assert_eq(local.query_idx + AB::Expr::ONE, local.num_queries);

// num_queries is constrained via the bus interaction with WhirRoundAir
self.verify_queries_bus.receive(
    builder,
    proof_idx,
    VerifyQueriesBusMessage {
        tidx: local.tidx,
        whir_round: local.whir_round,
        num_queries: local.num_queries,
        omega: local.omega,
        gamma: local.gamma,
        pre_claim: local.pre_claim,
        post_claim: local.post_claim,
    },
    local.is_first_in_round,
);

builder
    .when(is_same_round.clone())
    .assert_one(next.tidx - local.tidx);
builder
    .when(is_same_round.clone())
    .assert_eq(next.omega, local.omega);
assert_array_eq(
    &mut builder.when(is_same_round.clone()),
    next.gamma,
    local.gamma,
);
assert_array_eq(
    &mut builder.when(is_same_round.clone()),
    next.gamma_pow,
    ext_field_multiply::<AB::Expr>(local.gamma, local.gamma_pow),
);
assert_array_eq(
    &mut builder.when(is_same_round.clone()),
    next.pre_claim,
    ext_field_add::<AB::Expr>(
        local.pre_claim,
        ext_field_multiply::<AB::Expr>(local.gamma_pow, local.yi),
    ),
);
assert_array_eq(
    &mut builder.when(is_same_round.clone()),
    next.post_claim,
    local.post_claim,
);
assert_array_eq(
    &mut builder.when(local.is_enabled - is_same_round.clone()),
    ext_field_add::<AB::Expr>(
        local.pre_claim,
        ext_field_multiply::<AB::Expr>(local.yi, local.gamma_pow),
    ),
    local.post_claim,
);

    self.transcript_bus
        .sample(builder, proof_idx, local.tidx, local.sample, is_enabled);
    self.query_bus.send(
        builder,
        proof_idx,
        WhirQueryBusMessage {
            whir_round: local.whir_round.into(),
            query_idx: local.query_idx.into() + AB::Expr::ONE,
            value: [
                local.zi.into(),
                AB::Expr::ZERO,
                AB::Expr::ZERO,
                AB::Expr::ZERO,
            ],
        },
        is_enabled,
    );
    self.verify_query_bus.send(
        builder,
        proof_idx,
        VerifyQueryBusMessage {
            whir_round: local.whir_round,
            query_idx: local.query_idx,
            merkle_idx_bit_src: local.sample,
            zi_root: local.zi_root,
            zi: local.zi,
            yi: local.yi,
        },
        is_enabled,
    );
    self.exp_bits_len_bus.lookup_key(
        builder,
        ExpBitsLenMessage {
            base: local.omega.into(),
            bit_src: local.sample.into(),
            num_bits: AB::Expr::from_usize(self.initial_log_domain_size - self.k)
                - local.whir_round,
            result: local.zi_root.into(),
        },
        is_enabled,
    );
}

NestedForLoopSubAir::<5>.eval(
    builder,
    (
        NestedForLoopIoCols {
            is_enabled: local.flags[0],
            counter: [
                local.proof_idx,
                local.query_idx,
                local.coset_idx,
                local.commit_idx,
                local.col_chunk_idx,
            ],
            is_first: [
                local.is_first_in_proof,
                local.is_first_in_query,
                local.is_first_in_coset,
                local.is_first_in_commit,
                local.flags[0],
            ],
        }
        .map_into(),
        NestedForLoopIoCols {
            is_enabled: next.flags[0],
            counter: [
                next.proof_idx,
                next.query_idx,
                next.coset_idx,
                next.commit_idx,
                next.col_chunk_idx,
            ],
            is_first: [
                next.is_first_in_proof,
                next.is_first_in_query,
                next.is_first_in_coset,
                next.is_first_in_commit,
                next.flags[0],
            ],
        }
        .map_into(),
    ),
);

let is_enabled = local.flags[0];
for flag in local.flags {
    builder.assert_bool(flag);
}
for i in 0..CHUNK - 1 {
    builder.when(local.flags[i + 1]).assert_one(local.flags[i]);
}

self.whir_mu_bus.receive(
    builder,
    local.proof_idx,
    WhirMuMessage {
        mu: local.mu.map(Into::into),
    },
    local.is_first_in_proof,
);

assert_array_eq(&mut builder.when(is_same_proof.clone()), local.mu, next.mu);
assert_array_eq(
    &mut builder.when(local.is_first_in_coset),
    local.mu_pows_even_clamped[0],
    [AB::F::ONE, AB::F::ZERO, AB::F::ZERO, AB::F::ZERO],
);
assert_array_eq(
    &mut builder.when(local.is_first_in_coset),
    local.codeword_value_acc,
    [AB::F::ZERO; 4],
);

builder
    .when(is_enabled - is_same_query.clone())
    .assert_eq(local.coset_idx, AB::Expr::from_usize((1 << self.k) - 1));

let select = |cond: AB::Expr, a: [AB::Expr; D_EF], b: [AB::Expr; D_EF]| {
    array::from_fn(|j| a[j].clone() + cond.clone() * (b[j].clone() - a[j].clone()))
};

// Even-power recurrence.
// Starting from mu^(min(b + 2k, opened_row_len - 1)):
// - apply +1 if flags[2k+1] = 1
// - apply another +1 if flags[2k+2] = 1
for k in 0..CHUNK / 2 - 1 {
    let p0 = local.mu_pows_even_clamped[k].map(Into::into);
    let p1 = ext_field_multiply(local.mu, p0.clone());
    let p2 = ext_field_multiply(local.mu, p1.clone());
    let p_after_odd = select(local.flags[2 * k + 1].into(), p0, p1);
    let p_after_even = select(local.flags[2 * k + 2].into(), p_after_odd, p2);
    assert_array_eq(builder, local.mu_pows_even_clamped[k + 1], p_after_even);
}

// mu_pow_last_clamped stores mu^(min(b + CHUNK - 1, opened_row_len - 1)).
// Starting from mu_pows_even_clamped[last] = mu^(min(b + CHUNK - 2, opened_row_len - 1)),
// apply one final +1 step iff the last slot is valid.
{
    let last = CHUNK / 2 - 1;
    let p_last = local.mu_pows_even_clamped[last].map(Into::into);
    let p_last_next = ext_field_multiply(local.mu, p_last.clone());
    let expected_last = select(local.flags[CHUNK - 1].into(), p_last, p_last_next);
    assert_array_eq(builder, local.mu_pow_last_clamped, expected_last);
}

assert_array_eq(
    &mut builder.when(is_same_coset_idx.clone()),
    next.mu_pows_even_clamped[0],
    ext_field_multiply(local.mu, local.mu_pow_last_clamped),
);

let mut codeword_value_slice_acc: [AB::Expr; D_EF] =
    local.codeword_value_acc.map(Into::into);
for (i, mu_pow_acc_odd_unclamped) in mu_pows_acc_odd_unclamped.iter().enumerate() {
    builder
        .when(is_same_commit.clone())
        .when(AB::Expr::ONE - next.flags[i])
        .assert_eq(local.post_state[i], next.pre_state[i]);

    // flags[i] masks invalid slots, so those contribute zero regardless
    // of pre_state[i].
    let contribution: [AB::Expr; D_EF] = ext_field_multiply_scalar(
        mu_pow_acc_odd_unclamped.clone(),
        local.pre_state[i] * local.flags[i],
    );
    codeword_value_slice_acc = ext_field_add(codeword_value_slice_acc, contribution);

    builder
        .when(local.is_first_in_commit)
        .assert_zero(local.pre_state[CHUNK + i]);
    builder
        .when(local.is_first_in_commit)
        .when(AB::Expr::ONE - local.flags[i])
        .assert_zero(local.pre_state[i]);
    builder
        .when(is_same_commit.clone())
        .assert_eq(next.pre_state[CHUNK + i], local.post_state[CHUNK + i]);
    builder
        .when(is_same_commit.clone())
        .assert_one(local.flags[i]);

    let col_idx =
        local.col_chunk_idx * AB::Expr::from_usize(CHUNK) + AB::Expr::from_usize(i);

    self.stacking_indices_bus.lookup_key(
        builder,
        local.proof_idx,
        StackingIndexMessage {
            commit_idx: local.commit_idx.into(),
            col_idx: col_idx.clone(),
        },
        local.flags[i],
    );
}

assert_array_eq(
    builder,
    local.codeword_value_next_acc,
    codeword_value_slice_acc,
);

self.verify_query_bus.receive(
    builder,
    local.proof_idx,
    VerifyQueryBusMessage {
        whir_round: AB::Expr::ZERO,
        query_idx: local.query_idx.into(),
        merkle_idx_bit_src: local.merkle_idx_bit_src.into(),
        zi_root: local.zi_root.into(),
        zi: local.zi.into(),
        yi: local.yi.map(Into::into),
    },
    local.is_first_in_query,
);

self.poseidon_permute_bus.lookup_key(
    builder,
    Poseidon2PermuteMessage {
        input: local.pre_state,
        output: local.post_state,
    },
    is_enabled,
);

let is_last_in_commit = is_enabled - is_same_commit.clone();
self.merkle_verify_bus.send(
    builder,
    local.proof_idx,
    MerkleVerifyBusMessage {
        merkle_idx_bit_src: local.merkle_idx_bit_src.into(),
        current_idx_bit_src: local.merkle_idx_bit_src.into(),
        total_depth: AB::Expr::from_usize(self.initial_log_domain_size + 1),
        height: AB::Expr::ZERO,
        is_leaf: AB::Expr::ONE,
        leaf_sub_idx: local.coset_idx.into(),
        value: array::from_fn(|i| local.post_state[i].into()),
        commit_major: AB::Expr::ZERO,
        commit_minor: local.commit_idx.into(),
    },
    is_last_in_commit,
);

builder
    .when(local.is_first_in_query)
    .assert_eq(local.twiddle, AB::Expr::ONE);
builder
    .when(is_same_coset_idx.clone())
    .assert_eq(next.twiddle, local.twiddle);
builder
    .when((is_enabled - is_same_coset_idx.clone()) * next.flags[0])
    .assert_eq(next.twiddle, local.twiddle * omega_k);

builder
    .when(is_same_query.clone())
    .assert_eq(next.zi_root, local.zi_root);
builder
    .when(is_same_query.clone())
    .assert_eq(next.zi, local.zi);
builder
    .when(is_same_query.clone())
    .assert_eq(next.merkle_idx_bit_src, local.merkle_idx_bit_src);
assert_array_eq(&mut builder.when(is_same_query.clone()), next.yi, local.yi);
self.folding_bus.send(
    builder,
    local.proof_idx,
    WhirFoldingBusMessage {
        whir_round: AB::Expr::ZERO,
        query_idx: local.query_idx.into(),
        height: AB::Expr::ZERO,
        coset_shift: local.zi_root.into(),
        coset_idx: local.coset_idx.into(),
        coset_size: AB::Expr::from_usize(1 << self.k),
        twiddle: local.twiddle.into(),
        value: local.codeword_value_next_acc.map(Into::into),
        z_final: local.zi.into(),
        y_final: local.yi.map(Into::into),
    },
    is_enabled - is_same_coset_idx.clone(),
);

let is_same_query = next.is_enabled - next.is_first_in_query;

let max_coset_idx = AB::Expr::from_usize((1 << self.k) - 1);
builder
    .when(local.is_enabled - is_same_query.clone())
    .assert_eq(local.coset_idx, max_coset_idx);

NestedForLoopSubAir.eval(
    builder,
    (
        NestedForLoopIoCols {
            is_enabled: local.is_enabled.into(),
            counter: [
                local.proof_idx.into(),
                local.whir_round - AB::F::ONE,
                local.query_idx.into(),
                local.coset_idx.into(),
            ],
            is_first: [
                local.is_first_in_proof,
                local.is_first_in_round,
                local.is_first_in_query,
                local.is_enabled,
            ]
            .map(Into::into),
        },
        NestedForLoopIoCols {
            is_enabled: next.is_enabled.into(),
            counter: [
                next.proof_idx.into(),
                next.whir_round - AB::F::ONE,
                next.query_idx.into(),
                next.coset_idx.into(),
            ],
            is_first: [
                next.is_first_in_proof,
                next.is_first_in_round,
                next.is_first_in_query,
                next.is_enabled,
            ]
            .map(Into::into),
        },
    ),
);

self.verify_query_bus.receive(
    builder,
    local.proof_idx,
    VerifyQueryBusMessage {
        whir_round: local.whir_round,
        query_idx: local.query_idx,
        merkle_idx_bit_src: local.merkle_idx_bit_src,
        zi_root: local.zi_root,
        zi: local.zi,
        yi: local.yi,
    },
    local.is_first_in_query,
);

self.folding_bus.send(
    builder,
    local.proof_idx,
    WhirFoldingBusMessage {
        whir_round: local.whir_round.into(),
        query_idx: local.query_idx.into(),
        height: AB::Expr::ZERO,
        coset_shift: local.zi_root.into(),
        coset_size: AB::Expr::from_usize(1 << self.k),
        coset_idx: local.coset_idx.into(),
        twiddle: local.twiddle.into(),
        value: local.value.map(Into::into),
        z_final: local.zi.into(),
        y_final: local.yi.map(Into::into),
    },
    local.is_enabled,
);

let pre_state: [AB::Expr; POSEIDON2_WIDTH] = from_fn(|i| {
    if i < D_EF {
        local.value[i].into()
    } else {
        AB::Expr::ZERO
    }
});
self.poseidon2_compress_bus.lookup_key(
    builder,
    Poseidon2CompressMessage {
        input: pre_state,
        output: local.value_hash.map(Into::into),
    },
    local.is_enabled,
);

self.merkle_verify_bus.send(
    builder,
    local.proof_idx,
    MerkleVerifyBusMessage {
        value: local.value_hash.map(Into::into),
        merkle_idx_bit_src: local.merkle_idx_bit_src.into(),
        current_idx_bit_src: local.merkle_idx_bit_src.into(),
        // There are two parts: hashing leaves (depth k) and merkle proof
        total_depth: AB::Expr::from_usize(self.initial_log_domain_size + 1)
            - local.whir_round,
        height: AB::Expr::ZERO,
        is_leaf: AB::Expr::ONE,
        leaf_sub_idx: local.coset_idx.into(),
        commit_major: local.whir_round.into(),
        commit_minor: AB::Expr::ZERO,
    },
    local.is_enabled,
);

fn eval(&self, builder: &mut AB) {
    let main = builder.main();

    let local = main.row_slice(0).expect("window should have two elements");
    let local: &WhirFoldingCols<AB::Var> = (*local).borrow();

    builder.assert_bool(local.is_valid);
    builder.assert_bool(local.is_root);
    builder.when(local.is_root).assert_one(local.is_valid);
    builder.when(local.is_root).assert_one(local.twiddle);
    builder.when(local.is_root).assert_zero(local.coset_idx);
    builder
        .when(local.is_root)
        .assert_eq(local.height, AB::F::from_usize(self.k));
    builder
        .when(local.is_root)
        .assert_eq(local.z_final, local.coset_shift * local.coset_shift);
    assert_array_eq(&mut builder.when(local.is_root), local.value, local.y_final);

    let x = local.twiddle * local.coset_shift;

    let term = ext_field_multiply::<AB::Expr>(
        ext_field_subtract::<AB::Expr>(local.alpha, base_to_ext::<AB::Expr>(x.clone())),
        ext_field_subtract::<AB::Expr>(local.left_value, local.right_value),
    );
    // value = left_value + term / (2x)
    assert_array_eq(
        builder,
        ext_field_multiply::<AB::Expr>(
            ext_field_subtract::<AB::Expr>(local.value, local.left_value),
            base_to_ext::<AB::Expr>(x * AB::Expr::TWO),
        ),
        term,
    );

fn eval(&self, builder: &mut AB) {
    let main = builder.main();
    let local_row = main.row_slice(0).expect("window should have two elements");
    let local: &FinalyPolyMleEvalCols<AB::Var> = (*local_row).borrow();

    builder.assert_bool(local.is_enabled);
    builder.assert_bool(local.is_root);
    builder.when(local.layer).assert_one(local.is_enabled);
    builder.when(local.node_idx).assert_one(local.is_enabled);

    let is_nonleaf = local.layer_inv * local.layer;
    builder.when(local.layer).assert_one(is_nonleaf.clone());

    builder.when(local.is_root).assert_one(local.is_enabled);

    let num_vars = AB::Expr::from_usize(self.num_vars);
    builder
        .when(local.is_root)
        .assert_eq(local.layer, num_vars.clone());
    builder
        .when(local.is_root)
        .assert_eq(local.num_nodes_in_layer, AB::Expr::ONE);
    builder.when(local.is_root).assert_zero(local.node_idx);

    let is_node_idx_nonzero = local.node_idx * local.node_idx_inv;
    builder
        .when(local.node_idx)
        .assert_one(is_node_idx_nonzero.clone());

    let var_idx = AB::Expr::from_usize(self.num_sumcheck_rounds + self.num_vars) - local.layer;

    builder.assert_eq(
        local.is_nonleaf_and_first_in_layer,
        is_nonleaf.clone() * (local.is_enabled - is_node_idx_nonzero.clone()),
    );
    let is_nonleaf_and_not_first_in_layer = is_nonleaf.clone() * is_node_idx_nonzero;

// Each non-leaf node needs the opening point for its layer. The first
// node (node_idx=0) receives it from the permutation bus and registers
// it on a lookup bus for the remaining nodes in this layer. The fact
// that we receive on the permutation bus receive ensures each key is
// registered exactly once on the lookup bus (since the producers send
// each key once).
self.whir_opening_point_bus.receive(
    builder,
    local.proof_idx,
    WhirOpeningPointMessage {
        idx: var_idx.clone(),
        value: local.point.map(Into::into),
    },
    local.is_nonleaf_and_first_in_layer,
);
self.whir_opening_point_lookup_bus.add_key_with_lookups(
    builder,
    local.proof_idx,
    WhirOpeningPointMessage {
        idx: var_idx.clone(),
        value: local.point.map(Into::into),
    },
    local.is_nonleaf_and_first_in_layer * (local.num_nodes_in_layer - AB::Expr::ONE),
);
self.whir_opening_point_lookup_bus.lookup_key(
    builder,
    local.proof_idx,
    WhirOpeningPointMessage {
        idx: var_idx,
        value: local.point.map(Into::into),
    },
    is_nonleaf_and_not_first_in_layer,
);

let left_idx = local.node_idx;
let right_idx = left_idx + local.num_nodes_in_layer;
let child_depth = local.layer - AB::Expr::ONE;

self.folding_bus.receive(
    builder,
    local.proof_idx,
    FinalPolyFoldingMessage {
        proof_idx: local.proof_idx.into(),
        depth: child_depth.clone(),
        node_idx: left_idx.into(),
        num_nodes_in_layer: local.num_nodes_in_layer * AB::Expr::TWO,
        tidx_final_poly_start: local.tidx_final_poly_start.into(),
        value: local.left_value.map(Into::into),
    },
    is_nonleaf.clone(),
);
self.folding_bus.receive(
    builder,
    local.proof_idx,
    FinalPolyFoldingMessage {
        proof_idx: local.proof_idx.into(),
        depth: child_depth,
        node_idx: right_idx.clone(),
        num_nodes_in_layer: local.num_nodes_in_layer * AB::Expr::TWO,
        tidx_final_poly_start: local.tidx_final_poly_start.into(),
        value: local.right_value.map(Into::into),
    },
    is_nonleaf.clone(),
);
self.folding_bus.send(
    builder,
    local.proof_idx,
    FinalPolyFoldingMessage {
        proof_idx: local.proof_idx,
        depth: local.layer,
        node_idx: local.node_idx,
        num_nodes_in_layer: local.num_nodes_in_layer,
        tidx_final_poly_start: local.tidx_final_poly_start,
        value: local.value,
    },
    local.is_enabled - local.is_root,
);

// Evaluation-form MLE folding: value = left + (right - left) * point
assert_array_eq(
    &mut builder.when(is_nonleaf.clone()),
    local.value.map(Into::into),
    ext_field_add::<AB::Expr>(
        local.left_value,
        ext_field_multiply::<AB::Expr>(
            ext_field_subtract::<AB::Expr>(local.right_value, local.left_value),
            local.point,
        ),
    ),
);
assert_array_eq(
    &mut builder.when(local.is_root),
    local.value.map(Into::into),
    local.result.map(Into::into),
);

    let is_leaf = local.is_enabled - is_nonleaf;
    let delta = AB::Expr::from_usize(D_EF);
    let tidx_node = local.tidx_final_poly_start + local.node_idx * delta;
    self.transcript_bus.observe_ext(
        builder,
        local.proof_idx,
        tidx_node,
        local.value,
        is_leaf.clone(),
    );

    let total_whir_queries = AB::Expr::from_usize(self.total_whir_queries);
    self.final_poly_bus.add_key_with_lookups(
        builder,
        local.proof_idx,
        WhirFinalPolyBusMessage {
            idx: local.node_idx,
            coeff: local.value,
        },
        is_leaf.clone() * total_whir_queries.clone(),
    );

    self.final_poly_mle_eval_bus.receive(
        builder,
        local.proof_idx,
        FinalPolyMleEvalMessage {
            tidx: local.tidx_final_poly_start.into(),
            num_whir_rounds: AB::Expr::from_usize(self.num_whir_rounds),
            value: ext_field_multiply(local.value, local.eq_alpha_u),
        },
        local.is_root,
    );
    self.eq_alpha_u_bus.receive(
        builder,
        local.proof_idx,
        WhirEqAlphaUMessage {
            value: local.eq_alpha_u,
        },
        local.is_root,
    );
}

let k_whir_f = AB::Expr::from_usize(self.k_whir);
let eq_phase_len =
    k_whir_f.clone() * (AB::Expr::from_usize(self.num_whir_rounds - 1) - local.whir_round);
let final_poly_phase_len = AB::Expr::from_usize((1 << self.log_final_poly_len) - 1);

let round_base = (local.whir_round + AB::Expr::ONE) * k_whir_f;

let proof_idx = local.proof_idx;

builder.assert_bool(local.phase_idx);
builder.when(local.phase_idx).assert_one(local.is_enabled);
let local_is_eq_phase = local.is_enabled - local.phase_idx;

let is_same_proof = next.is_enabled - next.is_first_in_proof;
let is_same_round = next.is_enabled - next.is_first_in_round;
let is_same_query = next.is_enabled - next.is_first_in_query;
let is_same_phase = next.is_enabled - next.is_first_in_phase;

builder
    .when(local.phase_idx)
    .when(local.is_enabled - is_same_phase.clone())
    .assert_eq(local.eval_idx, final_poly_phase_len.clone());

builder
    .when(AB::Expr::ONE - local.phase_idx)
    .when(local.is_enabled - is_same_phase.clone())
    .assert_eq(local.eval_idx, eq_phase_len - AB::Expr::ONE);

assert_array_eq(
    &mut builder.when(local_is_eq_phase.clone()),
    next.query_pow,
    ext_field_multiply::<AB::Expr>(local.query_pow, local.query_pow),
);

assert_array_eq(
    &mut builder.when(local.phase_idx * is_same_query.clone()),
    next.query_pow,
    local.query_pow,
);

// The value of post_horner_acc *after* this inner-most loop iteration, if we are not in
// eq_phase. Degree 2.
let post_horner_acc = ext_field_add(
    ext_field_multiply(local.horner_acc, local.query_pow),
    local.final_poly_coeff,
);

assert_array_eq(
    &mut builder.when(local.is_first_in_query),
    local.gamma_eq_acc,
    local.gamma_pow,
);
assert_array_eq(
    &mut builder.when(local_is_eq_phase.clone()),
    next.gamma_eq_acc,
    ext_field_multiply(local.gamma_eq_acc, eq_1(local.alpha, local.query_pow)),
);
assert_array_eq(
    &mut builder.when((AB::Expr::ONE - local_is_eq_phase.clone()) * is_same_query.clone()),
    next.gamma_eq_acc,
    local.gamma_eq_acc,
);
assert_array_eq(
    &mut builder.when(local.is_first_in_round),
    local.gamma_pow,
    local.gamma,
);
assert_array_eq(
    &mut builder.when(is_same_query.clone()),
    next.gamma_pow,
    local.gamma_pow,
);
assert_array_eq(
    &mut builder.when(is_same_round.clone() * next.is_first_in_query),
    next.gamma_pow,
    ext_field_multiply(local.gamma_pow, local.gamma),
);

builder.assert_bool(local.do_carry);
builder.assert_eq(
    local.is_enabled * local.do_carry,
    (is_same_proof.clone() - is_same_query.clone())
        * (AB::Expr::ONE - local.is_query_zero * local.is_last_round),
);

let gamma_eq_post = ext_field_multiply(local.gamma_eq_acc, post_horner_acc.clone());

builder
    .when(local_is_eq_phase.clone())
    .assert_zeros(local.horner_acc);
builder
    .when(local.is_first_in_query)
    .assert_zeros(local.horner_acc);
builder
    .when(local_is_eq_phase.clone())
    .assert_zeros(local.final_poly_coeff);
assert_array_eq(
    &mut builder.when(is_same_query.clone()),
    next.horner_acc,
    post_horner_acc.clone(),
);
let contrib = ext_field_multiply::<AB::Expr>(local.gamma_eq_acc, post_horner_acc.clone());
let post_final_value_acc = ext_field_add(local.final_value_acc, contrib);
assert_array_eq(
    &mut builder.when(local.do_carry),
    next.final_value_acc,
    post_final_value_acc,
);
assert_array_eq(
    &mut builder.when(
        (is_same_proof.clone() - is_same_query.clone())
            * (local.is_query_zero * local.is_last_round),
    ),
    next.final_value_acc,
    local.final_value_acc,
);

self.query_bus.receive(
    builder,
    proof_idx,
    WhirQueryBusMessage {
        whir_round: local.whir_round,
        query_idx: local.query_idx,
        value: local.query_pow,
    },
    local.is_first_in_query,
);
let alpha_idx = round_base + local.eval_idx;
self.alpha_bus.lookup_key(
    builder,
    proof_idx,
    WhirAlphaMessage {
        idx: alpha_idx,
        challenge: local.alpha.map(Into::into),
    },
    local_is_eq_phase.clone(),
);
self.gamma_bus.receive(
    builder,
    proof_idx,
    WhirGammaMessage {
        idx: local.whir_round,
        challenge: local.gamma,
    },
    local.is_first_in_round,
);
assert_array_eq(
    &mut builder.when(is_same_round.clone()),
    local.gamma,
    next.gamma,
);
let is_last = local.is_enabled - is_same_proof.clone();
let final_value = ext_field_add(local.final_value_acc, gamma_eq_post);
self.final_poly_query_eval_bus.receive(
    builder,
    proof_idx,
    FinalPolyQueryEvalMessage {
        last_whir_round: AB::Expr::from_usize(self.num_whir_rounds),
        value: final_value,
    },
    is_last,
);

let coeff_idx = final_poly_phase_len - local.eval_idx;
self.final_poly_bus.lookup_key(
    builder,
    proof_idx,
    WhirFinalPolyBusMessage {
        idx: coeff_idx,
        coeff: local.final_poly_coeff.map(Into::into),
    },
    local.is_enabled * local.phase_idx,
);
